import{_ as e,a as r,M as t,o}from"./chunks/framework.BzjwFSRk.js";const b=JSON.parse('{"title":"Project Hub","description":"","frontmatter":{"title":"Project Hub","date":"2019-02-07","cover":"af-.png"},"headers":[],"relativePath":"practice/event/projecthub/index.md","filePath":"practice/event/projecthub/index.md"}'),l={name:"practice/event/projecthub/index.md"};function h(i,a,n,d,c,s){return o(),r("div",null,[...a[0]||(a[0]=[t('<h3 id="центр-реализации-творческих-проектов" tabindex="-1">Центр реализации творческих проектов <a class="header-anchor" href="#центр-реализации-творческих-проектов" aria-label="Permalink to &quot;Центр реализации творческих проектов&quot;">​</a></h3><h1 id="заяви-свои-творческии-проект-прямо-сеичас-и-участвуи-с-ним-на-фестивале-antifactory-25—26-мая" tabindex="-1">Заяви свой творческий проект прямо сейчас и участвуй с ним на <a href="http://antifactory.ru" class="external-link" target="_blank" rel="noreferrer">фестивале Antifactory</a> 25—26 мая! <a class="header-anchor" href="#заяви-свои-творческии-проект-прямо-сеичас-и-участвуи-с-ним-на-фестивале-antifactory-25—26-мая" aria-label="Permalink to &quot;Заяви свой творческий проект прямо сейчас и участвуй с ним на [фестивале Antifactory](http://antifactory.ru) 25—26 мая!&quot;">​</a></h1><p><strong>Project Hub</strong> – экспериментальное пространство для начинающих умельцев на фестивале крафтовых производств и DIY-культуры <strong>Antifactory</strong>. Это стартовая площадка для тех, кто только начинает создавать вещи своими руками и хочет представить их заинтересованной публике единомышленников. За 3 месяца у каждого желающего есть возможность подготовить свой ремесленный проект, пройти отбор и показать свои достижения 40 000 гостей фестиваля.</p><p>Команда проекта <strong>OOLEY</strong> представит в пространстве <strong>Project Hub</strong> результаты своих исследований свободного творчества, присоединяйтесь!</p><h1 id="возможности-участия" tabindex="-1">Возможности участия <a class="header-anchor" href="#возможности-участия" aria-label="Permalink to &quot;Возможности участия&quot;">​</a></h1><h2 id="🛍-ярмарка-начинании" tabindex="-1">🛍 Ярмарка начинаний <a class="header-anchor" href="#🛍-ярмарка-начинании" aria-label="Permalink to &quot;🛍 Ярмарка начинаний&quot;">​</a></h2><p>Выставка-продажа работ начинающих DIY-щиков. Если тебе знакома радость творчества, ты создаешь изделия в новых для тебя направлениях, но пока не решаешься продавать работы – попробуй начать с нами! Проведи один день на ярмарке и представь свои произведения гостям фестиваля. Ты можешь начать прямо сейчас готовить коллекцию к фестивалю.</p><h2 id="🚀-проектная-лаборатория" tabindex="-1">🚀 Проектная лаборатория <a class="header-anchor" href="#🚀-проектная-лаборатория" aria-label="Permalink to &quot;🚀 Проектная лаборатория&quot;">​</a></h2><p>В этой зоне на фестивале мы подскажем, как превратить твою новую идею в полноценный проект: сформулируем цели, построим план работ и проконсультируем по необходимым ресурсам. Возможно, ты сможешь реализовать свой проект сразу в зоне мастерских фестиваля! Также здесь ты найдешь возможность обменяться личным опытом с другими умельцами и DIY-щиками.</p><h2 id="💸-аукцион-произведении" tabindex="-1">💸 Аукцион произведений <a class="header-anchor" href="#💸-аукцион-произведении" aria-label="Permalink to &quot;💸 Аукцион произведений&quot;">​</a></h2><p>Здесь ты сможешь презентовать и выставить на аукцион три своих работы. Коротко представь свой проект и позволь аукционисту найти того, кто достойно оценит и поддержит твои начинания. Это отличный игровой формат чтобы узнать, насколько твои работы интересны окружающим, и чтобы найти самого заинтересованного покупателя.</p><h3 id="подать-заявку-посетить-площадку-лаборатории-на-фестивале-и-получить-консультации-по-вашим-проектам-можно-совершенно-бесплатно" tabindex="-1">Подать заявку, посетить площадку лаборатории на фестивале и получить консультации по вашим проектам можно совершенно бесплатно! <a class="header-anchor" href="#подать-заявку-посетить-площадку-лаборатории-на-фестивале-и-получить-консультации-по-вашим-проектам-можно-совершенно-бесплатно" aria-label="Permalink to &quot;Подать заявку, посетить площадку лаборатории на фестивале и получить консультации по вашим проектам можно совершенно бесплатно!&quot;">​</a></h3><h2 id="📄-условия-участия-в-ярмарке-и-аукционе" tabindex="-1">📄 Условия участия в ярмарке и аукционе <a class="header-anchor" href="#📄-условия-участия-в-ярмарке-и-аукционе" aria-label="Permalink to &quot;📄 Условия участия в ярмарке и аукционе&quot;">​</a></h2><h5 id="организационныи-взнос" tabindex="-1">Организационный взнос <a class="header-anchor" href="#организационныи-взнос" aria-label="Permalink to &quot;Организационный взнос&quot;">​</a></h5><h2 id="_2000-₽" tabindex="-1">2000 ₽ <a class="header-anchor" href="#_2000-₽" aria-label="Permalink to &quot;2000 ₽&quot;">​</a></h2><h5 id="пост-репост" tabindex="-1">+ пост/репост <a class="header-anchor" href="#пост-репост" aria-label="Permalink to &quot;+ пост/репост&quot;">​</a></h5><h5 id="присылаи-заявку-если" tabindex="-1">Присылай заявку если: <a class="header-anchor" href="#присылаи-заявку-если" aria-label="Permalink to &quot;Присылай заявку если:&quot;">​</a></h5><ul><li>Ты — настоящий новичок: увлекаешься своим ремеслом недавно, твои работы – это результаты обучения и экспериментов. Заявить можно как готовые коллекции, так и сделать что-то к фестивалю и прислать нам заявку.</li><li>Ты никогда раньше не выставлял работы на ярмарках.</li><li>Ты хочешь получить опыт участия в публичных мероприятиях, чтобы далее развиваться в этой сфере, продавать свои произведения, проводить мастер-классы.</li></ul><h5 id="для-участия-в-ярмарке-и-аукционе-необходимо" tabindex="-1">Для участия в ярмарке и аукционе необходимо: <a class="header-anchor" href="#для-участия-в-ярмарке-и-аукционе-необходимо" aria-label="Permalink to &quot;Для участия в ярмарке и аукционе необходимо:&quot;">​</a></h5><ul><li>Подать заявку <strong>до 1 мая 2019</strong></li><li>Сделать репост/пост о Project Hub на Antifactory fest, где ты напишешь, что хочешь презентовать на фестивале, и указать ссылку на публикацию в своей анкете. Мы хотим, чтобы как можно больше творческих людей узнали о такой возможности!</li><li>Если ты пройдешь отбор, оплатить орг-взнос в размере 2000 рублей. Собранные средства пойдут на организацию пространства ярмарки.</li></ul><h5 id="организационныи-взнос-включает" tabindex="-1">Организационный взнос включает: <a class="header-anchor" href="#организационныи-взнос-включает" aria-label="Permalink to &quot;Организационный взнос включает:&quot;">​</a></h5><ul><li><ul><li>один день участия в ярмарке <ul><li>1 выступление — презентация своих работ</li><li>3 лота на аукционе</li></ul></li></ul></li></ul><p>Выбирай, что тебе ближе или вписывайся во всё.</p><h1 id="каждыи-участник-получает" tabindex="-1">Каждый участник получает <a class="header-anchor" href="#каждыи-участник-получает" aria-label="Permalink to &quot;Каждый участник получает&quot;">​</a></h1><h1 id="🛍" tabindex="-1">🛍 <a class="header-anchor" href="#🛍" aria-label="Permalink to &quot;🛍&quot;">​</a></h1><h4 id="один-день-на-ярмарке" tabindex="-1">Один день на ярмарке <a class="header-anchor" href="#один-день-на-ярмарке" aria-label="Permalink to &quot;Один день на ярмарке&quot;">​</a></h4><h2 id="🎁" tabindex="-1">🎁 <a class="header-anchor" href="#🎁" aria-label="Permalink to &quot;🎁&quot;">​</a></h2><h4 id="_5-минут-презентации" tabindex="-1">5 минут презентации <a class="header-anchor" href="#_5-минут-презентации" aria-label="Permalink to &quot;5 минут презентации&quot;">​</a></h4><h2 id="💸" tabindex="-1">💸 <a class="header-anchor" href="#💸" aria-label="Permalink to &quot;💸&quot;">​</a></h2><h4 id="_3-лота-на-аукционе" tabindex="-1">3 лота на аукционе <a class="header-anchor" href="#_3-лота-на-аукционе" aria-label="Permalink to &quot;3 лота на аукционе&quot;">​</a></h4><h2 id="🔗" tabindex="-1">🔗 <a class="header-anchor" href="#🔗" aria-label="Permalink to &quot;🔗&quot;">​</a></h2><h4 id="анонс-в-соц-сетях" tabindex="-1">Анонс в соц. сетях <a class="header-anchor" href="#анонс-в-соц-сетях" aria-label="Permalink to &quot;Анонс в соц. сетях&quot;">​</a></h4><h2 id="🚀" tabindex="-1">🚀 <a class="header-anchor" href="#🚀" aria-label="Permalink to &quot;🚀&quot;">​</a></h2><h4 id="консультации-по-проекту" tabindex="-1">Консультации по проекту <a class="header-anchor" href="#консультации-по-проекту" aria-label="Permalink to &quot;Консультации по проекту&quot;">​</a></h4><h2 id="🌊" tabindex="-1">🌊 <a class="header-anchor" href="#🌊" aria-label="Permalink to &quot;🌊&quot;">​</a></h2><h4 id="полезныи-опыт-и-знакомства" tabindex="-1">Полезный опыт и знакомства <a class="header-anchor" href="#полезныи-опыт-и-знакомства" aria-label="Permalink to &quot;Полезный опыт и знакомства&quot;">​</a></h4><h2 id="денис-и-анна-старовы" tabindex="-1">Денис и Анна Старовы <a class="header-anchor" href="#денис-и-анна-старовы" aria-label="Permalink to &quot;Денис и Анна Старовы&quot;">​</a></h2><h5 id="кураторы-проекта" tabindex="-1">Кураторы проекта <a class="header-anchor" href="#кураторы-проекта" aria-label="Permalink to &quot;Кураторы проекта&quot;">​</a></h5><p>Привет! Мы — авторы проекта <a href="https://ooley.ru" target="_blank" rel="noreferrer">OOLEY</a>, посвященного движению открытых мастерских, и организаторы летнего творческого лагеря для взрослых <a href="https://xn--lomamp-krf.ooley.ru" class="external-link" target="_blank" rel="noreferrer">ЛОМ: Лесные открытые мастерские</a>.</p><p>На протяжении нескольких лет мы исследуем свободное творчество и социальные платформы для его развития. Внедряем проектный подход в творчество и с большой заботой поддерживаем начинающих умельцев! Мы будем принимать и отбирать заявки, консультировать по проектам и готовы ответить на все организационные вопросы.</p><h4 id="если-ты-хоть-раз-воплощал-задуманное-сам-ты-знаешь-что-такое-реализовывать-проект" tabindex="-1">Если ты хоть раз воплощал задуманное сам, ты знаешь, что такое реализовывать проект. <a class="header-anchor" href="#если-ты-хоть-раз-воплощал-задуманное-сам-ты-знаешь-что-такое-реализовывать-проект" aria-label="Permalink to &quot;Если ты хоть раз воплощал задуманное сам, ты знаешь, что такое реализовывать проект.&quot;">​</a></h4><p>Нам нравится проектный подход в творчестве, потому что этот метод помогает не застревать и не терять вдохновение. Поступательно двигаться к поставленным целям, разбивая длинный путь на отдельные этапы, а затем — циклично воплощать проекты различного масштаба. Мы помогаем осваивать проектный подход и применять его в любых направлениях творчества. И приглашаем вас делиться опытом и результатами ваших реализованных проектов.</p><p><a href="/theory/system/projectapp/">Подробнее о проектном подходе &gt;</a></p><h2 id="🎨-творческие-направления" tabindex="-1">🎨 Творческие направления <a class="header-anchor" href="#🎨-творческие-направления" aria-label="Permalink to &quot;🎨 Творческие направления&quot;">​</a></h2><p>Углубляешься в тонкости ремесла или сочетаешь различные техники и технологии?</p><h2 id="воздух" tabindex="-1">Воздух <a class="header-anchor" href="#воздух" aria-label="Permalink to &quot;Воздух&quot;">​</a></h2><h4 id="краски-бумага-нити-пряжа-ткань" tabindex="-1">Краски, бумага, нити, пряжа, ткань <a class="header-anchor" href="#краски-бумага-нити-пряжа-ткань" aria-label="Permalink to &quot;Краски, бумага, нити, пряжа, ткань&quot;">​</a></h4><h2 id="вода" tabindex="-1">Вода <a class="header-anchor" href="#вода" aria-label="Permalink to &quot;Вода&quot;">​</a></h2><h4 id="дерево-пластики-смолы" tabindex="-1">Дерево, пластики, смолы <a class="header-anchor" href="#дерево-пластики-смолы" aria-label="Permalink to &quot;Дерево, пластики, смолы&quot;">​</a></h4><h2 id="огонь" tabindex="-1">Огонь <a class="header-anchor" href="#огонь" aria-label="Permalink to &quot;Огонь&quot;">​</a></h2><h4 id="электричество-температуры-химия-металлы-и-механизмы" tabindex="-1">Электричество, температуры, химия, металлы и механизмы <a class="header-anchor" href="#электричество-температуры-химия-металлы-и-механизмы" aria-label="Permalink to &quot;Электричество, температуры, химия, металлы и механизмы&quot;">​</a></h4><h2 id="земля" tabindex="-1">Земля <a class="header-anchor" href="#земля" aria-label="Permalink to &quot;Земля&quot;">​</a></h2><h4 id="камень-глина-гипс-бетон-и-прочие-массы" tabindex="-1">Камень, глина, гипс, бетон и прочие массы <a class="header-anchor" href="#камень-глина-гипс-бетон-и-прочие-массы" aria-label="Permalink to &quot;Камень, глина, гипс, бетон и прочие массы&quot;">​</a></h4><h2 id="🖊-заявка" tabindex="-1">🖊 Заявка <a class="header-anchor" href="#🖊-заявка" aria-label="Permalink to &quot;🖊 Заявка&quot;">​</a></h2><p>Мы принимаем заявки на участие <strong>до 1 мая</strong>. Количество мест на ярмарке и аукционе ограничено. Выбор участников производится организаторами на основании предоставленных примеров работ и уникальности заявленных проектов. После заполнения формы мы обязательно свяжемся с вами в течение недели!</p>',55)])])}const q=e(l,[["render",h]]);export{b as __pageData,q as default};
